recommended.code:
const refreshCurrentSession = async () => {
  const session = await sessionRepository.getFromCookies()

  if (!session) return null
  if (!session.needsRefresh) return session

  const refreshedSession = await authProvider.refresh(session)
  await sessionRepository.save(refreshedSession)

  return refreshedSession
}

const onAppFocus = async () => {
  await fetch("/api/auth/session", { method: "POST" })
}

